var net  = global.get('net');
var maps = global.get('cotMaps');

// Pre-built CoT XML passthrough (drawing → ATAK)
if (msg.payload && typeof msg.payload === 'string' && msg.payload.startsWith('<?xml')) {
    var s = context.get('socket');
    if (s && typeof s.write === 'function' && !s.destroyed) {
        s.write(msg.payload);
        node.log('Drawing CoT sent (' + msg.payload.length + ' bytes)');
    } else {
        node.warn('FTS socket not ready, drawing CoT dropped');
    }
    return null;
}

var socket  = context.get('socket');
var kaTimer = context.get('kaTimer');

// Validate socket is a real net.Socket, not a stale deserialized JSON object
if (socket && typeof socket.write !== 'function') {
    context.set('socket', null);
    socket = null;
}

if (socket && !socket.destroyed) {
    return null;
}

if (kaTimer) { clearInterval(kaTimer); context.set('kaTimer', null); }

function connectToFTS() {
    var existing = context.get('socket');
    if (existing && typeof existing.write === 'function' && !existing.destroyed) return;

    var myUid = 'CrypTAK-NR-WebMap';

    var s = new net.Socket();
    var buf = '';

    s.connect(8087, 'freetakserver', function() {
        node.log('FTS connected as ' + myUid);
        s.write(maps.makeSA(myUid));
        var timer = setInterval(function() {
            if (s && !s.destroyed) {
                s.write(maps.makeSA(myUid));
            } else {
                clearInterval(timer);
                context.set('kaTimer', null);
            }
        }, 240000);
        context.set('kaTimer', timer);
    });

    s.on('data', function(data) {
        context.set('retryCount', 0);
        buf += data.toString();
        var endTag = '</event>';
        var idx;
        while ((idx = buf.indexOf(endTag)) !== -1) {
            var xml = buf.substring(0, idx + endTag.length);
            buf = buf.substring(idx + endTag.length);
            try {
                var marker = maps.parseCotToMarker(xml);
                if (!marker) {
                    // Try drawing parser for u-d-* types
                    var typeCheck = xml.match(/\btype="([^"]+)"/);
                    if (typeCheck && typeCheck[1].startsWith("u-d-")) {
                        var drawing = maps.parseCotDrawing(xml);
                        if (drawing) {
                            node.send({ payload: drawing });
                        }
                    }
                    continue;
                }

                var cache = flow.get('takMarkers') || {};
                if (marker.deleted) {
                    delete cache[marker.name];
                    flow.set('takMarkers', cache);
                    node.send({ payload: marker });
                    continue;
                }

                // Tracker overrides: apply WebMap-set affiliation, asset type, and SIDC
                if (marker._tracker) {
                    var affOverrides = flow.get('trackerAffiliations') || {};
                    var aff = affOverrides[marker.name];
                    if (aff) {
                        marker.iconColor = maps.colorMap[aff] || marker.iconColor;
                        marker.layer = maps.affiliationNames[aff] || marker.layer;
                        marker._baseColor = marker.iconColor;
                    }
                    // Apply asset type SIDC (overrides default icon)
                    var assetTypes = flow.get('trackerAssetTypes') || {};
                    var assetType = assetTypes[marker.name];
                    if (assetType) {
                        marker.SIDC = maps.buildTrackerSIDC(aff || 'f', assetType);
                        delete marker.icon;
                    } else {
                        // Fall back to icon override if no asset type set
                        var iconOverrides = flow.get('trackerIcons') || {};
                        var customIcon = iconOverrides[marker.name];
                        if (customIcon) {
                            marker.icon = customIcon;
                        }
                    }
                }

                cache[marker.name] = marker;

                // Purge stale markers from cache (every 100th write)
                var writeCount = (context.get('writeCount') || 0) + 1;
                context.set('writeCount', writeCount);
                if (writeCount % 100 === 0) {
                    var now = Date.now();
                    var cKeys = Object.keys(cache);
                    for (var ci = 0; ci < cKeys.length; ci++) {
                        var cm = cache[cKeys[ci]];
                        if (cm && cm._staleMs && cm._staleMs < now) {
                            delete cache[cKeys[ci]];
                        }
                    }
                }
                flow.set('takMarkers', cache);
                node.send({ payload: marker });

                // Tracker trail: store position history and emit polyline
                if (marker._tracker) {
                    var history = flow.get('trackerHistory') || {};
                    var trail = history[marker.name] || [];
                    trail.push({ lat: marker.lat, lon: marker.lon, ts: Date.now() });

                    // Trim to 24h
                    var cutoff = Date.now() - 24 * 3600000;
                    trail = trail.filter(function(p) { return p.ts >= cutoff; });
                    history[marker.name] = trail;
                    flow.set('trackerHistory', history);

                    // Emit polyline to worldmap
                    var trailDuration = flow.get('trailDuration');
                    if (trailDuration === undefined || trailDuration === null) trailDuration = 3600000;
                    if (trailDuration > 0 && trail.length >= 2) {
                        var displayCutoff = Date.now() - trailDuration;
                        var displayTrail = trail.filter(function(p) { return p.ts >= displayCutoff; });
                        if (displayTrail.length >= 2) {
                            node.send({ payload: {
                                name: 'trail-' + marker.name,
                                line: displayTrail.map(function(p) { return { lat: p.lat, lng: p.lon }; }),
                                color: marker.iconColor,
                                weight: 3,
                                opacity: 0.6,
                                layer: 'TAK Tracks',
                                ttl: 600
                            }});
                        }
                    }
                }
            } catch(e) { node.warn('CoT parse error: ' + e.message); }
        }
    });

    s.on('error', function(e) {
        node.warn('FTS socket error: ' + e.message);
        var t = context.get('kaTimer');
        if (t) { clearInterval(t); context.set('kaTimer', null); }
        s.destroy();
        context.set('socket', null);
    });

    s.on('close', function() {
        node.warn('FTS socket closed (' + myUid + ')');
        var t = context.get('kaTimer');
        if (t) { clearInterval(t); context.set('kaTimer', null); }
        context.set('socket', null);
        if (context.get('closing')) return;
        var retries = context.get('retryCount') || 0;
        if (retries < 5) {
            context.set('retryCount', retries + 1);
            var delay = (retries + 1) * 2000;
            node.warn('Retry ' + (retries + 1) + '/5 in ' + (delay/1000) + 's');
            setTimeout(function() { connectToFTS(); }, delay);
        } else {
            node.warn('FTS: 5 retries exhausted, waiting for inject cycle');
            context.set('retryCount', 0);
        }
    });

    context.set('socket', s);
}

context.set('closing', false);
connectToFTS();

// Periodic color refresh — recalculate fade colors every 30s and remove expired markers.
// Clear stale deserialized timer from persisted context
var _rt = context.get('refreshTimer');
if (_rt && typeof _rt.ref !== 'function') {
    context.set('refreshTimer', null);
}

if (!context.get('refreshTimer')) {
    var refreshTimer = setInterval(function() {
        var cache = flow.get('takMarkers') || {};
        var result = maps.refreshMarkerColors(cache);

        // Send updated colors to worldmap
        for (var i = 0; i < result.updated.length; i++) {
            node.send({ payload: result.updated[i] });
        }

        // Remove fully expired markers
        for (var j = 0; j < result.expired.length; j++) {
            node.send({ payload: { name: result.expired[j], deleted: true } });
            delete cache[result.expired[j]];
        }

        if (result.updated.length > 0 || result.expired.length > 0) {
            flow.set('takMarkers', cache);
        }
        if (result.expired.length > 0) {
            node.log('Refresh: updated ' + result.updated.length + ' colors, removed ' + result.expired.length + ' expired');
        }

        // Refresh tracker trails — re-emit polylines with updated colors and TTL
        var history = flow.get('trackerHistory') || {};
        var trailDuration = flow.get('trailDuration');
        if (trailDuration === undefined || trailDuration === null) trailDuration = 3600000;
        if (trailDuration > 0) {
            var displayCutoff = Date.now() - trailDuration;
            var trackerKeys = Object.keys(history);
            for (var t = 0; t < trackerKeys.length; t++) {
                var tName = trackerKeys[t];
                var tMarker = cache[tName];
                if (!tMarker) continue;
                var tTrail = history[tName].filter(function(p) { return p.ts >= displayCutoff; });
                if (tTrail.length >= 2) {
                    node.send({ payload: {
                        name: 'trail-' + tName,
                        line: tTrail.map(function(p) { return { lat: p.lat, lng: p.lon }; }),
                        color: tMarker.iconColor,
                        weight: 3,
                        opacity: 0.6,
                        layer: 'TAK Tracks',
                        ttl: 600
                    }});
                }
            }
        }
    }, 30000);
    context.set('refreshTimer', refreshTimer);
}

return null;

finalize:
context.set('closing', true);
var s = context.get('socket');  if (s && typeof s.destroy === 'function') s.destroy();
var t = context.get('kaTimer'); if (t && typeof t.ref === 'function') clearInterval(t);
var rt = context.get('refreshTimer'); if (rt && typeof rt.ref === 'function') clearInterval(rt);

