if (!msg.payload || !msg.payload.features) { node.warn('States GeoJSON failed'); return null; }
flow.set('statesGeoJSON', msg.payload);
node.log('Cached ' + msg.payload.features.length + ' state features');
msg.payload = { command: { map: {
    overlay: 'US States',
    geojson: flow.get('statesGeoJSON'),
    opt: { style: "function() { return { color: '#444', weight: 1.5, fill: false } }" },
    visible: false, fit: false, clickable: false
}}};
return msg;

if (!msg.payload || !msg.payload.features) { node.warn('Counties GeoJSON failed'); return null; }
flow.set('countiesGeoJSON', msg.payload);
node.log('Cached ' + msg.payload.features.length + ' county features');
msg.payload = { command: { map: {
    overlay: 'US Counties',
    geojson: flow.get('countiesGeoJSON'),
    opt: { style: "function() { return { color: '#888', weight: 0.7, fill: false } }" },
    visible: false, fit: false, clickable: false
}}};
return msg;

var data = msg.payload;
if (!data || !data.features) { node.warn('NOAA API failed: ' + JSON.stringify(msg.statusCode)); return null; }

var now = Date.now();
var sevStyle = {
    'Extreme':  { stroke: '#CC0000', fill: '#FF0000', 'fill-opacity': 0.20 },
    'Severe':   { stroke: '#CC4400', fill: '#FF6600', 'fill-opacity': 0.075 },
    'Moderate': { stroke: '#AAAA00', fill: '#FFEE00', 'fill-opacity': 0.11 },
    'Minor':    { stroke: '#0055AA', fill: '#3399FF', 'fill-opacity': 0.075 },
    'Unknown':  { stroke: '#555555', fill: '#999999', 'fill-opacity': 0.05 }
};

var features = [];
data.features.forEach(function(f) {
    if (!f.geometry) return;
    if (f.properties.expires && new Date(f.properties.expires).getTime() < now) return;
    var sev = f.properties.severity || 'Unknown';
    var sp  = sevStyle[sev] || sevStyle['Unknown'];
    var feat = JSON.parse(JSON.stringify(f));
    // worldmap's overlay+geojson handler reads feature.properties.style
    // with keys: stroke, stroke-width, fill, fill-opacity
    feat.properties.style = {
        stroke: sp.stroke,
        'stroke-width': 2,
        fill: sp.fill,
        'fill-opacity': sp['fill-opacity']
    };
    feat.properties.name = feat.properties.event || 'Alert';
    features.push(feat);
});

node.log('NOAA: ' + features.length + ' active alerts');
var fc = { type: 'FeatureCollection', features: features };
flow.set('noaaGeoJSON', fc);

// worldmap's overlay+geojson handler automatically removes the old overlay
// before creating the new one (line ~2850 in worldmap.js), so no clear needed.
msg.payload = { command: { map: {
    overlay: 'NOAA Alerts',
    geojson: fc,
    visible: true, fit: false
}}};
return msg;

// Load node registry from nodes.yaml (single source of truth)
var registry = global.get('nodesRegistry');
if (!registry || !registry.nodes) {
    node.warn('nodesRegistry not loaded — check nodes.yaml mount');
    return null;
}

var ownedNodes = {};
var ownedFlat = {};
var nodes = registry.nodes;
var names = Object.keys(nodes);

for (var i = 0; i < names.length; i++) {
    var name = names[i];
    var cfg = nodes[name];
    var id = cfg.id;
    if (!id) continue; // skip nodes without hex ID (not yet provisioned)

    ownedNodes[id] = {
        name: name,
        bridge: !!cfg.bridge,
        cotType: cfg.cot_type || 'a-f-G-E-S'
    };
    ownedFlat[id] = name;
}

flow.set('meshOwnedNodes', ownedFlat);
flow.set('meshOwnedConfig', ownedNodes);

// Pre-seed registry so owned nodes show correct names immediately
var meshRegistry = flow.get('meshRegistry') || {};
var ids = Object.keys(ownedNodes);
for (var j = 0; j < ids.length; j++) {
    meshRegistry[ids[j]] = meshRegistry[ids[j]] || { id: ids[j] };
    if (!meshRegistry[ids[j]].name) meshRegistry[ids[j]].name = ownedNodes[ids[j]].name;
}
flow.set('meshRegistry', meshRegistry);

node.log('Mesh whitelist loaded from nodes.yaml: ' + ids.length + ' owned nodes');
return null;

if (msg.topic.indexOf('/json/') === -1) return null;

var payload = msg.payload;
if (!payload || !payload.from) return null;

var nodeId   = '!' + payload.from.toString(16).padStart(8, '0');
var msgType  = payload.type;
var ts       = payload.timestamp || Math.floor(Date.now() / 1000);
var registry = flow.get('meshRegistry') || {};
registry[nodeId] = registry[nodeId] || { id: nodeId };

// Capture link-quality from every packet (how the bridge hears this node)
var pktSnr  = typeof payload.snr       === 'number' ? payload.snr       : null;
var pktHops = typeof payload.hops_away === 'number' ? payload.hops_away : null;
var pktRssi = typeof payload.rssi      === 'number' ? payload.rssi      : null;
if (pktSnr  !== null) registry[nodeId].snrToBridge  = pktSnr;
if (pktHops !== null) registry[nodeId].hopsToBridge = pktHops;
if (pktRssi !== null) registry[nodeId].rssi         = pktRssi;
registry[nodeId].lastHeard = ts;

if (msgType === 'nodeinfo' && payload.payload) {
    var info = payload.payload;
    // Don't overwrite whitelist display names for owned nodes
    var ownedFlat = flow.get('meshOwnedNodes') || {};
    if (!ownedFlat[nodeId]) {
        registry[nodeId].name = info.longname || info.shortname || nodeId;
    }
    registry[nodeId].shortName = info.shortname || '';
    if (typeof info.hardware === 'number') registry[nodeId].hwModel = info.hardware;
    if (typeof info.role     === 'number') registry[nodeId].role    = info.role;
    flow.set('meshRegistry', registry);
    return null;
}

if (msgType === 'position' && payload.payload) {
    var pos = payload.payload;
    var lat = (pos.latitude_i  || 0) / 1e7;
    var lon = (pos.longitude_i || 0) / 1e7;

    if (lat !== 0 || lon !== 0) {
        registry[nodeId].lat = lat;
        registry[nodeId].lon = lon;
        registry[nodeId].alt = pos.altitude || 0;
    }
    flow.set('meshRegistry', registry);
    if (lat === 0 && lon === 0) return null;

    var topoLines = rebuildTopologyLines(nodeId, flow, registry);
    if (topoLines.length === 0) return null;
    return topoLines.map(function(l) { return { payload: l }; });
}

if (msgType === 'telemetry' && payload.payload) {
    var t = payload.payload;
    if (typeof t.battery_level       === 'number') registry[nodeId].battery     = t.battery_level;
    if (typeof t.voltage             === 'number') registry[nodeId].voltage     = t.voltage;
    if (typeof t.channel_utilization === 'number') registry[nodeId].channelUtil = t.channel_utilization;
    if (typeof t.air_util_tx         === 'number') registry[nodeId].airUtilTx   = t.air_util_tx;
    if (typeof t.uptime_seconds      === 'number') registry[nodeId].uptime      = t.uptime_seconds;
    flow.set('meshRegistry', registry);
    return null;
}

if (msgType === 'neighborinfo' && payload.payload) {
    var ni = payload.payload;
    var neighbors = ni.neighbors || [];
    var topology = flow.get('meshTopology') || {};
    topology[nodeId] = { ts: Date.now(), neighbors: {} };
    for (var j = 0; j < neighbors.length; j++) {
        var nb = neighbors[j];
        var nbId = '!' + nb.node_id.toString(16).padStart(8, '0');
        topology[nodeId].neighbors[nbId] = nb.snr || 0;
    }
    flow.set('meshTopology', topology);
    flow.set('meshRegistry', registry);

    var lines = rebuildTopologyLines(nodeId, flow, registry);
    if (lines.length === 0) return null;
    return lines.map(function(l) { return { payload: l }; });
}

flow.set('meshRegistry', registry);
return null;

// ── helpers ───────────────────────────────────────────────────────────────

function snrToLinkStyle(snr) {
    if (snr >= 5)  return { color: '#00DD00', weight: 3 };
    if (snr >= 0)  return { color: '#AADD00', weight: 2 };
    if (snr >= -7) return { color: '#FFAA00', weight: 2 };
    return { color: '#FF4444', weight: 1 };
}

function rebuildTopologyLines(changedNodeId, flow, registry) {
    var topology = flow.get('meshTopology') || {};
    var lines = [];
    var seen = {};
    var allSources = Object.keys(topology);
    for (var s = 0; s < allSources.length; s++) {
        var fromId = allSources[s];
        var entry = topology[fromId];
        if (!entry || !entry.neighbors) continue;
        var nbKeys = Object.keys(entry.neighbors);
        for (var n = 0; n < nbKeys.length; n++) {
            var toId = nbKeys[n];
            if (fromId !== changedNodeId && toId !== changedNodeId) continue;
            var edgePair = [fromId, toId].sort();
            var edgeName = 'link-' + edgePair[0].replace('!','') + '-' + edgePair[1].replace('!','');
            if (seen[edgeName]) continue;
            seen[edgeName] = true;

            var fromNode = registry[fromId];
            var toNode   = registry[toId];
            if (!fromNode || !fromNode.lat || !toNode || !toNode.lat) continue;

            var snr = entry.neighbors[toId];
            if (topology[toId] && topology[toId].neighbors && topology[toId].neighbors[fromId] !== undefined) {
                snr = Math.max(snr, topology[toId].neighbors[fromId]);
            }
            var style = snrToLinkStyle(snr);
            lines.push({
                name:    edgeName,
                line:    [
                    { lat: fromNode.lat, lng: fromNode.lon },
                    { lat: toNode.lat,   lng: toNode.lon   }
                ],
                color:   style.color,
                weight:  style.weight,
                opacity: 0.75,
                layer:   'Mesh Links',
                ttl:     1800,
                tooltip: snr.toFixed(1) + ' dB'
            });
        }
    }
    return lines;
}

if (!msg.payload || msg.payload.action !== 'connected') return null;
var maps = global.get('cotMaps');
var sid = msg._sessionid;
var msgs = [];

// Branding
msgs.push({ payload: { command: { toptitle: 'CrypTAK WebMap' } }, _sessionid: sid });
msgs.push({ payload: { command: { toplogo: '/cryptak-logo.png' } }, _sessionid: sid });
msgs.push({ payload: { command: { coords: 'mgrs' } }, _sessionid: sid });
var legend = flow.get('legendHtml');
if (legend) msgs.push({ payload: { command: { legend: legend } }, _sessionid: sid });

// GeoJSON overlays
var stGeo = flow.get('statesGeoJSON');
if (stGeo) msgs.push({ payload: { command: { map: { overlay: 'US States', geojson: stGeo, opt: { style: "function() { return { color: '#444', weight: 1.5, fill: false } }" }, visible: false, fit: false, clickable: false } } }, _sessionid: sid });
var coGeo = flow.get('countiesGeoJSON');
if (coGeo) msgs.push({ payload: { command: { map: { overlay: 'US Counties', geojson: coGeo, opt: { style: "function() { return { color: '#888', weight: 0.7, fill: false } }" }, visible: false, fit: false, clickable: false } } }, _sessionid: sid });
var noaaGeo = flow.get('noaaGeoJSON');
// worldmap's overlay+geojson handler auto-replaces, no clear needed
if (noaaGeo && noaaGeo.features && noaaGeo.features.length > 0) msgs.push({ payload: { command: { map: { overlay: 'NOAA Alerts', geojson: noaaGeo, visible: true, fit: false } } }, _sessionid: sid });

// TAK markers (skip stale)
var takCache = flow.get('takMarkers') || {};
var tKeys = Object.keys(takCache);
var replayNow = Date.now();
var staleCount = 0;
for (var i = 0; i < tKeys.length; i++) {
    var m = takCache[tKeys[i]];
    if (m && m._staleMs && m._staleMs < replayNow) {
        staleCount++;
        continue;
    }
    msgs.push({ payload: Object.assign({}, m), _sessionid: sid });
}
if (staleCount > 0) node.log('Skipped ' + staleCount + ' stale markers during replay');

// Replay tracker trails
var history = flow.get('trackerHistory') || {};
var trailDuration = flow.get('trailDuration');
if (trailDuration === undefined || trailDuration === null) trailDuration = 3600000;
if (trailDuration > 0) {
    var displayCutoff = Date.now() - trailDuration;
    var tKeys2 = Object.keys(history);
    for (var k = 0; k < tKeys2.length; k++) {
        var tkName = tKeys2[k];
        var tkMarker = takCache[tkName];
        if (!tkMarker) continue;
        var tTrail = history[tkName].filter(function(p) { return p.ts >= displayCutoff; });
        if (tTrail.length >= 2) {
            msgs.push({ payload: {
                name: 'trail-' + tkName,
                line: tTrail.map(function(p) { return { lat: p.lat, lng: p.lon }; }),
                color: tkMarker.iconColor,
                weight: 3, opacity: 0.6,
                layer: 'TAK Tracks', ttl: 600
            }, _sessionid: sid });
        }
    }
}


// Mesh topology lines
var meshTopology = flow.get('meshTopology') || {};
var meshReg = flow.get('meshRegistry') || {};
var topoSeen = {};
var topoSources = Object.keys(meshTopology);
for (var tl = 0; tl < topoSources.length; tl++) {
    var tlFrom = topoSources[tl];
    var tlEntry = meshTopology[tlFrom];
    if (!tlEntry || !tlEntry.neighbors) continue;
    var tlNbs = Object.keys(tlEntry.neighbors);
    for (var tn = 0; tn < tlNbs.length; tn++) {
        var tlTo = tlNbs[tn];
        var epair = [tlFrom, tlTo].sort();
        var ename = 'link-' + epair[0].replace('!','') + '-' + epair[1].replace('!','');
        if (topoSeen[ename]) continue;
        topoSeen[ename] = true;
        var fnNode = meshReg[tlFrom];
        var tnNode = meshReg[tlTo];
        if (!fnNode || !fnNode.lat || !tnNode || !tnNode.lat) continue;
        var lsnr = tlEntry.neighbors[tlTo];
        if (meshTopology[tlTo] && meshTopology[tlTo].neighbors && meshTopology[tlTo].neighbors[tlFrom] !== undefined) {
            lsnr = Math.max(lsnr, meshTopology[tlTo].neighbors[tlFrom]);
        }
        var lStyle = maps.snrToLinkStyle(lsnr);
        var lcolor = lStyle.color, lweight = lStyle.weight;
        msgs.push({ payload: {
            name: ename,
            line: [{ lat: fnNode.lat, lng: fnNode.lon }, { lat: tnNode.lat, lng: tnNode.lon }],
            color: lcolor, weight: lweight, opacity: 0.75,
            layer: 'Mesh Links', ttl: 1800,
            tooltip: lsnr.toFixed(1) + ' dB'
        }, _sessionid: sid });
    }
}

node.log('Replaying ' + msgs.length + ' items to session ' + sid);
return [msgs];

var legendHtml = '<div style="font-family:sans-serif;font-size:12px;line-height:1.6;">'
    + '<b style="font-size:14px;">CrypTAK</b><br>'
    + '<hr style="margin:4px 0;">'
    + '<b>TAK Markers</b><br>'
    + '<span style="color:#0066FF;">&#9646;</span> Friendly (blue rectangle)<br>'
    + '<span style="color:#FF0000;">&#9670;</span> Hostile (red diamond)<br>'
    + '<span style="color:#FF8C00;">&#9670;</span> Suspect (orange diamond)<br>'
    + '<span style="color:#00AA00;">&#9632;</span> Neutral (green square)<br>'
    + '<span style="color:#CCCC00;">&#10048;</span> Unknown (yellow clover)<br>'
    + '<hr style="margin:4px 0;">'
    + '<b>TAK Drawings</b><br>'
    + 'User-drawn shapes from ATAK<br>'
    + '<hr style="margin:4px 0;">'
    + '<b>Mesh Nodes</b><br>'
    + '<span style="color:#0066FF;">&#9679;</span> Owned<br>'
    + '<span style="color:#00AA00;">&#9679;</span> Community<br>'
    + '<hr style="margin:4px 0;">'
    + '<b>NOAA Alerts</b><br>'
    + '<span style="color:#FF0000;">&#9632;</span> Extreme<br>'
    + '<span style="color:#FF6600;">&#9632;</span> Severe<br>'
    + '<span style="color:#FFEE00;">&#9632;</span> Moderate<br>'
    + '<span style="color:#3399FF;">&#9632;</span> Minor<br>'
    + '</div>';
flow.set('legendHtml', legendHtml);

// Pre-register all marker layers so toggles appear immediately,
// even before any real markers arrive. Sending a deleted placeholder
// creates the layer group in the control panel without leaving a marker.
var layerSeeds = [
    "TAK Friendly", "TAK Hostile", "TAK Suspect", "TAK Neutral",
    "TAK Unknown", "TAK Other", "TAK Tracks", "TAK Drawings", "Meshtastic"
];
var seedMsgs = layerSeeds.map(function(layerName) {
    return {
        payload: {
            name: "_seed_" + layerName,
            layer: layerName,
            deleted: true
        }
    };
});

var msgs = [
    { payload: { command: { toptitle: 'CrypTAK WebMap' } } },
    { payload: { command: { toplogo: '/cryptak-logo.png' } } },
    { payload: { command: { coords: 'mgrs' } } },
    { payload: { command: { legend: legendHtml } } }
];
return [msgs.concat(seedMsgs)];

var p = msg.payload;
if (!p || p.action !== 'draw') return null;

var now   = new Date().toISOString();
var stale = new Date(Date.now() + 24 * 3600000).toISOString();

function xmlEsc(s) {
    return String(s).replace(/&/g,'&amp;').replace(/'/g,'&apos;')
        .replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
var rawName = p.name || 'Drawing';
var uid  = 'NR-DRAW-' + rawName.replace(/[^a-zA-Z0-9_-]/g, '-');
var name = xmlEsc(rawName);

// CSS hex → signed 32-bit ARGB integer (TAK color format)
function cssToArgb(css, alpha) {
    alpha = (alpha !== undefined) ? alpha : 0xFF;
    var hex = (css || '#FFFFFF').replace('#', '');
    if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
    var r = parseInt(hex.substring(0, 2), 16) || 0;
    var g = parseInt(hex.substring(2, 4), 16) || 0;
    var b = parseInt(hex.substring(4, 6), 16) || 0;
    return ((alpha << 24) | (r << 16) | (g << 8) | b) | 0;
}

var opts = p.options || {};
var strokeColor = cssToArgb(opts.color || '#FFFF00');
var fillAlpha   = Math.round((opts.fillOpacity !== undefined ? opts.fillOpacity : 0.2) * 255);
var fillColor   = cssToArgb(opts.fillColor || opts.color || '#FFFF00', fillAlpha);
var weight      = opts.weight || 3.0;

function latlngsToLinks(arr) {
    return arr.map(function(pt) {
        return "<link point='" + pt.lat + "," + pt.lng + "'/>";
    }).join('');
}

function centroid(arr) {
    var lat = 0, lon = 0;
    arr.forEach(function(pt) { lat += pt.lat; lon += pt.lng; });
    return { lat: lat / arr.length, lon: lon / arr.length };
}

function eventWrap(type, centerLat, centerLon, detail) {
    return "<?xml version='1.0' encoding='UTF-8' standalone='yes'?>"
        + "<event version='2.0' uid='" + uid + "' type='" + type + "'"
        + " time='" + now + "' start='" + now + "' stale='" + stale + "' how='h-e'>"
        + "<point lat='" + centerLat + "' lon='" + centerLon + "'"
        + " hae='9999999.0' ce='9999999.0' le='9999999.0'/>"
        + "<detail>" + detail
        + "<strokeColor value='" + strokeColor + "'/>"
        + "<strokeWeight value='" + weight + "'/>"
        + "<fillColor value='" + fillColor + "'/>"
        + "<contact callsign='" + name + "'/>"
        + "<remarks>Drawn on CrypTAK WebMap</remarks>"
        + "<archive/><labels_on value='true'/>"
        + "</detail></event>";
}

var xml;

if (p.type === 'circlemarker' && p.lat && p.lon && p.radius) {
    xml = eventWrap('u-d-c-c', p.lat, p.lon,
        "<shape><ellipse major='" + p.radius + "' minor='" + p.radius + "' angle='360'/></shape>");

} else if (p.type === 'rectangle' && p.area) {
    var c = centroid(p.area);
    xml = eventWrap('u-d-r', c.lat, c.lon, latlngsToLinks(p.area));

} else if (p.type === 'polygon' && p.area) {
    var c = centroid(p.area);
    var links = latlngsToLinks(p.area);
    links += "<link point='" + p.area[0].lat + "," + p.area[0].lng + "'/>";
    xml = eventWrap('u-d-f', c.lat, c.lon, links);

} else if ((p.type === 'polyline' || p.type === 'route') && p.line) {
    var arr = p.line;
    if (Array.isArray(arr[0]) && arr[0].lat === undefined) arr = arr[0];
    var c = centroid(arr);
    xml = eventWrap('u-d-f', c.lat, c.lon, latlngsToLinks(arr));

} else {
    return null;
}

node.log('Draw→CoT: ' + p.type + ' "' + name + '" (' + xml.length + ' bytes)');
msg.payload = xml;
return msg;

var takCache = flow.get('takMarkers') || {};
var keys = Object.keys(takCache);
var clients = [];
var now = Date.now();

for (var i = 0; i < keys.length; i++) {
    var m = takCache[keys[i]];
    if (!m || !m.lat || !m.lon) continue;
    if (m._ageBased) continue;
    if (m._meshtastic) continue;
    if (m._staleMs && m._staleMs < now) continue;
    clients.push({
        callsign: m.name || keys[i],
        lat: m.lat,
        lon: m.lon,
        team: (m.layer || '').replace('TAK ', '')
    });
}

msg.payload = { clients: clients, updated: now };
msg.headers = { 'Content-Type': 'application/json' };
return msg;

var body = msg.payload;
var name = body && body.name;
var aff = body && body.affiliation;
if (!name || !aff || 'fnush'.indexOf(aff) === -1) {
    msg.payload = { error: 'name and affiliation (f/s/h) required' };
    msg.statusCode = 400;
    return msg;
}
var overrides = flow.get('trackerAffiliations') || {};
overrides[name] = aff;
flow.set('trackerAffiliations', overrides);

// Re-render the marker with new color and SIDC immediately
var maps = global.get('cotMaps');
var cache = flow.get('takMarkers') || {};
var marker = cache[name];
if (marker) {
    marker.iconColor = maps.colorMap[aff] || marker.iconColor;
    marker.layer = maps.affiliationNames[aff] || marker.layer;
    marker._baseColor = marker.iconColor;

    // Regenerate SIDC with new affiliation
    var assetTypes = flow.get('trackerAssetTypes') || {};
    var assetType = assetTypes[name] || 'vehicle';
    marker.SIDC = maps.buildTrackerSIDC(aff, assetType);
    delete marker.icon; // use SIDC, not FA icon

    // Rebuild popup with new color
    var r = maps.parseRemarks('');
    marker.popup = maps.buildPopup(name, r, marker.iconColor, marker._battery || 0, true);
    cache[name] = marker;
    flow.set('takMarkers', cache);
    node.send({ payload: marker });
}
msg.payload = { ok: true, name: name, affiliation: aff };
return msg;

var body = msg.payload;
var duration = body && body.duration;
if (duration === undefined || duration === null || typeof duration !== 'number') {
    msg.payload = { error: 'duration (ms) required' };
    msg.statusCode = 400;
    return msg;
}
flow.set('trailDuration', duration);

// If duration is 0, delete all trail polylines
if (duration === 0) {
    var history = flow.get('trackerHistory') || {};
    var keys = Object.keys(history);
    for (var i = 0; i < keys.length; i++) {
        node.send({ payload: { name: 'trail-' + keys[i], deleted: true } });
    }
}
msg.payload = { ok: true, duration: duration };
return msg;

var body = msg.payload;
var name = body && body.name;
var icon = body && body.icon;
if (!name || !icon) {
    msg.payload = { error: 'name and icon required' };
    msg.statusCode = 400;
    return msg;
}
var overrides = flow.get('trackerIcons') || {};
overrides[name] = icon;
flow.set('trackerIcons', overrides);

// Re-render the marker with new icon immediately
var maps = global.get('cotMaps');
var cache = flow.get('takMarkers') || {};
var marker = cache[name];
if (marker) {
    marker.icon = icon;
    // Rebuild popup
    var r = maps.parseRemarks('');
    marker.popup = maps.buildPopup(name, r, marker.iconColor, marker._battery || 0, true);
    cache[name] = marker;
    flow.set('takMarkers', cache);
    node.send({ payload: marker });
}
msg.payload = { ok: true, name: name, icon: icon };
return msg;

var registry    = flow.get('meshRegistry')    || {};
var ownedFlat   = flow.get('meshOwnedNodes')   || {};
var ownedConfig = flow.get('meshOwnedConfig')  || {};
var maps        = global.get('cotMaps');
var nowSec      = Math.floor(Date.now() / 1000);
var COMMUNITY_MAX_AGE = 48 * 3600; // prune community nodes not heard in 48h

var nodes = [];
var ids = Object.keys(registry);
for (var i = 0; i < ids.length; i++) {
    var id = ids[i];
    var n = registry[id];
    var isOwned = ownedFlat.hasOwnProperty(id);

    // Skip owned nodes that were pre-seeded but never actually heard
    if (isOwned && !n.lastHeard) continue;

    // Skip community nodes older than threshold
    if (!isOwned && n.lastHeard && (nowSec - n.lastHeard) > COMMUNITY_MAX_AGE) continue;
    if (!isOwned && !n.lastHeard) continue;

    // Bridge flag and cotType from config
    var cfg = ownedConfig[id] || {};
    var cotType = cfg.cotType || 'a-n-G-E-S'; // default: unknown ground equipment sensor

    // Generate SIDC from cotType
    var sidc = null;
    if (maps && maps.cotTypeToSIDC) {
        sidc = maps.cotTypeToSIDC(cotType.split('-'));
    }

    nodes.push({
        id:           id,
        name:         ownedFlat[id] || n.name || id,
        shortName:    n.shortName   || '',
        hwModel:      n.hwModel     !== undefined ? n.hwModel      : null,
        role:         n.role        !== undefined ? n.role         : null,
        lat:          n.lat         || null,
        lon:          n.lon         || null,
        battery:      n.battery     || 0,
        voltage:      n.voltage     || 0,
        channelUtil:  n.channelUtil || 0,
        airUtilTx:    n.airUtilTx   || 0,
        uptime:       n.uptime      || 0,
        snrToBridge:  n.snrToBridge  !== undefined ? n.snrToBridge  : null,
        hopsToBridge: n.hopsToBridge !== undefined ? n.hopsToBridge : null,
        rssi:         n.rssi         !== undefined ? n.rssi         : null,
        lastHeard:    n.lastHeard    || 0,
        hasPosition:  !!(n.lat && n.lon),
        owned:        isOwned,
        bridge:       !!cfg.bridge,
        sidc:         sidc
    });
}

// Owned first, then by lastHeard desc within each group
nodes.sort(function(a, b) {
    if (a.owned !== b.owned) return a.owned ? -1 : 1;
    return (b.lastHeard || 0) - (a.lastHeard || 0);
});

msg.payload = JSON.stringify({ nodes: nodes, ts: Date.now() });
msg.headers = { 'Content-Type': 'application/json' };
return msg;

var body = msg.payload;
var name = body && body.name;
var assetType = body && body.assetType;
var validTypes = ['vehicle', 'person', 'cargo', 'sensor', 'infrastructure'];
if (!name || !assetType || validTypes.indexOf(assetType) === -1) {
    msg.payload = { error: 'name and assetType (vehicle/person/cargo/sensor/infrastructure) required' };
    msg.statusCode = 400;
    return msg;
}

var assetTypes = flow.get('trackerAssetTypes') || {};
assetTypes[name] = assetType;
flow.set('trackerAssetTypes', assetTypes);

// Re-render the marker with new SIDC immediately
var maps = global.get('cotMaps');
var cache = flow.get('takMarkers') || {};
var marker = cache[name];
if (marker) {
    // Get current affiliation
    var affOverrides = flow.get('trackerAffiliations') || {};
    var aff = affOverrides[name] || 'f';

    // Regenerate SIDC with current affiliation + new asset type
    marker.SIDC = maps.buildTrackerSIDC(aff, assetType);
    delete marker.icon; // use SIDC, not FA icon

    // Update color/layer from affiliation
    marker.iconColor = maps.colorMap[aff] || marker.iconColor;
    marker.layer = maps.affiliationNames[aff] || marker.layer;
    marker._baseColor = marker.iconColor;

    // Rebuild popup
    var r = maps.parseRemarks('');
    marker.popup = maps.buildPopup(name, r, marker.iconColor, marker._battery || 0, true);
    cache[name] = marker;
    flow.set('takMarkers', cache);
    node.send({ payload: marker });
}
msg.payload = { ok: true, name: name, assetType: assetType };
return msg;
